import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch9: ScenarioQuestion[] = [
  q("sq-bg9-1",ip,"clinical_judgment","A patient develops autonomic dysreflexia after a spinal cord injury.","How would you manage autonomic dysreflexia?","Autonomic dysreflexia is a life-threatening emergency in patients with spinal cord injuries at T6 or above. It presents with sudden severe hypertension, pounding headache, flushing above the injury level, and bradycardia. I would sit the patient upright to lower BP, identify and remove the trigger (usually bladder distension or fecal impaction), loosen tight clothing, and administer antihypertensives if BP remains dangerously elevated.","Autonomic dysreflexia emergency management.","advanced"),
  q("sq-bg9-2",ip,"clinical_judgment","A patient with cirrhosis develops spontaneous bacterial peritonitis.","How would you recognize and manage SBP?","SBP presents with fever, abdominal pain, and altered mental status in a cirrhotic patient with ascites. Diagnosis requires paracentesis showing >250 PMN cells/mm3. I would ensure blood cultures and ascitic fluid cultures are obtained before antibiotics, administer empiric IV antibiotics per protocol, monitor closely for hepatorenal syndrome, and provide albumin infusion as ordered.","SBP recognition in cirrhosis.","advanced"),
  q("sq-bg9-3",ip,"clinical_judgment","A patient develops compartment syndrome after a tibial fracture.","What are the signs of compartment syndrome?","The classic signs are the 5 P's: Pain out of proportion to injury (especially with passive stretch), Pressure (tense compartment), Paresthesias, Pallor, and Pulselessness (late sign). I would not wait for all 5 P's—pain and pressure warrant urgent evaluation. Emergency fasciotomy is the treatment. Delayed diagnosis leads to permanent muscle and nerve damage.","Compartment syndrome early recognition.","advanced"),
  q("sq-bg9-4",ip,"behavioral","You are asked about handling a high-pressure situation.","Describe a time you performed under extreme pressure.","During a simulation involving simultaneous patient deterioration, I maintained composure by prioritizing based on ABCs, delegating specific tasks to team members, and communicating using closed-loop techniques. My instructor noted that my systematic approach prevented the team from becoming overwhelmed and ensured all critical interventions were completed.","Systematic pressure management with team coordination.","intermediate"),
  q("sq-bg9-5",ip,"behavioral","You are asked about continuous learning.","How do you stay current with nursing knowledge?","I subscribe to nursing journals, attend monthly CE webinars, participate in journal clubs when available, review updated clinical guidelines regularly, and engage in clinical discussions with experienced colleagues. I believe evidence-based practice requires ongoing commitment to learning—what I learned in school is the foundation, not the ceiling.","Ongoing professional education commitment.","beginner"),
  q("sq-bg9-6",ip,"scenario_responses","A patient asks if they can take their home medications while hospitalized.","How would you address home medication requests?","I would explain: 'For your safety, we need to manage all your medications through our pharmacy system. This allows us to check for interactions and ensure correct dosing. Please give any medications you brought from home to me so I can verify them with your physician. We want to make sure nothing is duplicated or missed.'","Home medication management in hospital.","beginner"),
  q("sq-bg9-7",ip,"scenario_responses","A patient asks about their lab results before the doctor visits.","How would you handle patient requests for lab results?","I would share objective information within my scope: 'Your hemoglobin is 10.2, which is a bit below normal. Your doctor will discuss what this means for your treatment plan when they visit today. Is there a specific result you are concerned about? I can make sure to flag your questions for the physician.'","Scope-appropriate lab result sharing.","beginner"),
  q("sq-bg9-8",ws,"prioritization","You receive four new admissions simultaneously.","How would you manage multiple simultaneous admissions?","I would triage by acuity: perform rapid safety assessments on all four, identifying which patients need immediate intervention. I would communicate the situation to the charge nurse for possible reassignment support, begin detailed admissions on the highest-acuity patient first, and delegate initial tasks for other patients.","Multiple admission triage strategy.","intermediate"),
  q("sq-bg9-9",ws,"prioritization","A patient requests a warm blanket while another patient's IV infiltrates.","Which takes priority?","The infiltrating IV takes priority—it requires immediate assessment to determine the severity, discontinuation of the IV, warm compress application, and site monitoring. An infiltrated IV can cause tissue damage, especially with vesicant medications. I would acknowledge the warm blanket request and provide it as soon as the IV issue is resolved.","Clinical urgency over comfort request.","beginner"),
  q("sq-bg9-10",ws,"prioritization","You have a patient with chest pain and another with a new onset seizure.","How would you prioritize these two emergencies?","Both are emergencies requiring immediate response. The seizure patient needs airway protection and safety measures first since seizures are immediately life-threatening. I would call for help so both can be addressed simultaneously. I would initiate seizure precautions while directing the responding nurse to the chest pain patient for ECG and assessment.","Dual emergency with help activation.","intermediate"),
  q("sq-bg9-11",ws,"delegation","A CNA asks if they can give oral medications to help you.","Can CNAs administer oral medications?","CNAs cannot administer medications—this is outside their scope of practice. I would explain: 'I appreciate your willingness to help, but medication administration requires a licensed nurse's assessment and verification. You can help me by getting vital signs on my other patients so I can focus on medication passes.'","Scope clarification with alternative task suggestion.","beginner"),
  q("sq-bg9-12",ws,"delegation","You need to delegate tracheostomy care to an LPN.","How would you delegate tracheostomy care?","I would verify the LPN's tracheostomy care competency, provide specific instructions about the type of trach, inner cannula care, suctioning parameters, and signs to report immediately. I would specify: 'Suction only PRN, not routinely. Use sterile technique. Report any difficulty passing the suction catheter, bloody secretions, or respiratory distress immediately.'","Competency-verified tracheostomy care delegation.","intermediate"),
  q("sq-bg9-13",ws,"patient_safety","A patient on bed rest develops calf pain and swelling.","What does unilateral calf pain and swelling suggest?","Unilateral calf pain with swelling in a bed-rest patient strongly suggests deep vein thrombosis. I would not massage the calf—this could dislodge a clot. I would elevate the affected leg, notify the provider for diagnostic ultrasound, check for Homan's sign carefully, and anticipate anticoagulation therapy. DVT can progress to life-threatening PE.","DVT recognition with clot mobilization avoidance.","intermediate"),
  q("sq-bg9-14",ws,"patient_safety","A patient on a PCA pump is found with the PCA button taped down.","How would you handle PCA misuse?","I would remove the tape immediately, assess the patient for respiratory depression, check vital signs and SpO2, and educate the patient about PCA safety: 'The button is designed so only you press it when you feel pain. Taping it down bypasses the safety feature and could cause a dangerous overdose.' I would notify the provider and document the incident.","PCA misuse intervention with patient education.","intermediate"),
  q("sq-bg9-15",ws,"patient_safety","A patient develops phlebitis at their IV site.","How would you manage IV-site phlebitis?","I would discontinue the IV immediately, apply a warm compress to the affected area, elevate the extremity, assess for more serious complications (thrombophlebitis, cellulitis), document the phlebitis using a standardized grading scale, restart the IV at a new site, and complete a safety report. Prevention includes site rotation and appropriate catheter size selection.","Phlebitis management with grading documentation.","beginner"),
  q("sq-bg9-16",ws,"medication_error","A patient is prescribed a medication that interacts with grapefruit.","How would you manage a drug-food interaction with grapefruit?","I would educate the patient about the interaction: 'Grapefruit can increase the amount of this medication in your blood to potentially dangerous levels. Please avoid grapefruit and grapefruit juice while taking this medication.' Common medications affected include statins, calcium channel blockers, and some immunosuppressants. I would notify dietary services.","Grapefruit interaction education.","beginner"),
  q("sq-bg9-17",ws,"medication_error","You are asked to give a medication you have never administered before.","How would you handle giving an unfamiliar medication?","I would look up the medication before administration: indication, dose range, route, administration rate, common side effects, and what to monitor. I would verify the order is appropriate for this patient. I would not administer any medication I do not understand. If unclear after research, I would consult the pharmacist.","Unknown medication research before administration.","beginner"),
  q("sq-bg9-18",ws,"handoff_communication","You need to hand off a patient with complex wound care.","How would you ensure wound care continuity during handoff?","I would describe: wound location, current size, wound bed characteristics, current dressing type and change frequency, treatment goals, any recent changes, and the next wound care assessment date. I would show photos if available in the chart. Wound care handoff should enable the receiving nurse to evaluate for changes.","Detailed wound care handoff communication.","beginner"),
  q("sq-bg9-19",ws,"difficult_coworkers","A colleague consistently interrupts you during patient education.","How would you handle interruptions during patient education?","I would address it privately: 'When you interrupt during my patient education sessions, it breaks the patient's concentration and undermines the information I am providing. If something is urgent, please signal me and I will step out. Otherwise, please wait until I am finished.' Consistent interruption is a respect issue that affects patient learning.","Patient education interruption boundary.","beginner"),
  q("sq-bg9-20",ws,"interdisciplinary_communication","A speech therapist recommends changing a patient's diet texture.","How would you implement a diet texture change recommendation?","I would verify the speech therapist's assessment, ensure a physician order is obtained for the diet change, update the dietary order in the system, notify dietary services, communicate the change to all nursing staff, update the bedside diet card, and educate the patient and family about the new diet requirements. Diet changes require clear multi-department communication.","Diet texture change implementation workflow.","beginner"),
  q("sq-bg9-21",ct,"first_shift","You are unsure about a unit-specific protocol.","How would you handle uncertainty about unit protocols?","I would ask before acting: 'I want to make sure I follow the correct protocol. Can you show me where the unit-specific protocols are located?' I would review the protocol thoroughly, ask clarifying questions, and bookmark frequently used protocols for quick reference. Unit-specific protocols may differ from textbook approaches.","Protocol verification before action.","beginner"),
  q("sq-bg9-22",ct,"first_shift","Your preceptor is unavailable and you encounter an unfamiliar situation.","What would you do when your preceptor is unavailable?","I would assess whether the situation requires immediate action or can wait. For urgent matters, I would contact the charge nurse. For non-urgent questions, I would research the topic using available resources and discuss with my preceptor when available. I would not attempt unfamiliar procedures without supervision during orientation.","Resource utilization when preceptor unavailable.","beginner"),
  q("sq-bg9-23",ct,"new_nurse_anxiety","You made a mistake and cannot stop thinking about it.","How would you process a clinical mistake emotionally?","I would acknowledge my feelings without catastrophizing. I would talk to a trusted colleague or my preceptor about what happened. I would analyze the error objectively: what factors contributed, what I could do differently, and what systems could prevent recurrence. I would then implement changes and move forward. Rumination without action is unproductive and harmful.","Constructive error processing versus rumination.","beginner"),
  q("sq-bg9-24",ct,"time_management","You are overwhelmed by the amount of charting required.","How would you manage documentation overload?","I would learn the EHR shortcuts and templates that speed documentation, develop a personal charting template for common assessments, chart in real-time rather than batching, use voice-to-text features if available, and ask experienced nurses for their documentation efficiency tips. I would also question whether all documentation is required or if some is redundant.","Documentation efficiency strategies.","beginner"),
  q("sq-bg9-25",ct,"documentation_challenges","You need to document a patient who leaves against medical advice.","What must AMA documentation include?","I would document: patient's expressed intent to leave, education provided about risks of leaving, specific risks discussed, patient's decision-making capacity assessment, their stated reason for leaving, physician notification, AMA form signed or refusal to sign, medications and prescriptions provided, instructions for when to seek emergency care, and follow-up arrangements.","Comprehensive AMA documentation.","intermediate"),
  q("sq-bg9-26",ct,"critical_thinking_drills","A patient's procalcitonin is elevated at 8 ng/mL.","What does an elevated procalcitonin indicate?","Procalcitonin above 2 ng/mL strongly suggests bacterial infection, and levels above 10 ng/mL indicate severe sepsis or septic shock. Unlike CRP, procalcitonin rises specifically with bacterial infections, not viral. I would assess for infection sources, ensure blood cultures are obtained, and correlate with the clinical picture. Procalcitonin trends are useful for monitoring antibiotic therapy effectiveness.","Procalcitonin as bacterial infection biomarker.","intermediate"),
  q("sq-bg9-27",ct,"critical_thinking_drills","A patient's magnesium is 1.0 mEq/L.","What does severe hypomagnesemia cause?","Magnesium of 1.0 (normal 1.5-2.5) is critically low and can cause life-threatening cardiac arrhythmias, seizures, and refractory hypokalemia. Magnesium is necessary for potassium channel function, so low magnesium prevents potassium correction. I would place on cardiac monitoring, administer IV magnesium replacement slowly, and check both potassium and calcium levels simultaneously.","Hypomagnesemia with refractory hypokalemia connection.","intermediate"),
  q("sq-bg9-28",ct,"critical_thinking_drills","A patient's albumin is 2.0 g/dL.","What does low albumin indicate clinically?","Albumin of 2.0 (normal 3.5-5.0) indicates severe malnutrition, chronic disease, liver dysfunction, or ongoing inflammation. Low albumin causes decreased oncotic pressure leading to edema, ascites, and increased drug toxicity for protein-bound medications. I would assess nutritional status, ensure adequate protein intake, anticipate medication dose adjustments, and monitor for peripheral edema.","Hypoalbuminemia clinical implications.","intermediate"),
  q("sq-bg9-29",pd,"professional_boundaries","A colleague shares personal information about a patient on social media.","How would you handle a HIPAA violation on social media?","I would address it immediately: 'You need to delete that post immediately—it contains identifiable patient information and violates HIPAA. Even without a name, if anyone could identify the patient from the details, it is a violation that could result in termination and legal consequences.' I would report the incident to the privacy officer.","Social media HIPAA violation intervention.","intermediate"),
  q("sq-bg9-30",pd,"ethical_dilemmas","A patient asks you to lie to their family about their condition.","How would you handle a patient requesting deception?","I would explore the request: 'I understand you may have reasons for not wanting your family to know certain things. I cannot lie, but I can help you control what information is shared. Would you like to discuss what you are comfortable with your family knowing? I can be present when you talk to them.'","Truthfulness with patient-controlled information sharing.","intermediate"),
  q("sq-bg9-31",pd,"advocacy","A patient with disabilities encounters accessibility barriers in the hospital.","How would you advocate for disability accessibility?","I would identify and report specific barriers, request appropriate accommodations, ensure assistive devices are available, modify care delivery to accommodate the disability, and advocate with administration for systemic accessibility improvements. I would treat the patient with the same respect and autonomy as any other patient while addressing practical barriers.","Disability accessibility advocacy.","intermediate"),
  q("sq-bg9-32",pd,"patient_communication","A patient uses medical terminology incorrectly and misunderstands their condition.","How would you correct medical misinformation gently?","I would not embarrass the patient: 'I want to make sure we are on the same page about your condition. Let me explain what your diagnosis means using everyday language, and you can tell me if that matches your understanding.' I would correct misunderstandings without making the patient feel foolish for their prior understanding.","Gentle medical misinformation correction.","beginner"),
  q("sq-bg9-33",pd,"workplace_bullying","A manager publicly criticizes your clinical decision.","How would you handle public criticism from management?","I would remain professional in the moment and request a private meeting: 'I would appreciate discussing this privately so I can fully understand your concerns and share my clinical reasoning.' Public criticism undermines authority and morale. I would document the incident and present my rationale with evidence during the private meeting.","Public criticism private redirection.","intermediate"),
  q("sq-bg9-34",cn,"job_offer_negotiation","An interviewer asks about your long-term commitment to their unit.","How would you address long-term commitment questions?","I would be honest about my interest: 'I am looking for a unit where I can build my career. I am committed to investing at least 2-3 years in developing my clinical expertise before considering any changes. Your unit's orientation program and professional development opportunities align with my long-term career goals.'","Honest commitment communication with realistic timeframe.","beginner"),
  q("sq-bg9-35",cn,"probation_period","You are not receiving enough feedback during probation.","How would you request more feedback?","I would be proactive: 'I value feedback for my professional growth and want to make sure I am meeting expectations. Could we schedule brief weekly check-ins where you share observations about my performance? I also welcome real-time feedback during shifts. Specific suggestions help me improve faster.'","Proactive feedback solicitation.","beginner"),
  q("sq-bg9-36",cn,"career_advancement","You want to develop expertise in trauma nursing.","How would you prepare for trauma nursing?","I would obtain TNCC certification, develop rapid assessment skills, gain experience in emergency settings, learn about trauma resuscitation protocols, develop comfort with high-acuity situations and rapid decision-making, and pursue CEN certification. Trauma nursing requires systematic assessment skills and the ability to manage multiple simultaneously injured patients.","Trauma nursing specialization pathway.","intermediate"),
  q("sq-bg9-37",cn,"performance_evaluation","You want to demonstrate leadership growth during your evaluation.","How would you showcase leadership development?","I would present specific examples: leading a patient care conference, mentoring a nursing student, initiating a quality improvement project, resolving a team conflict constructively, or taking charge nurse responsibility. I would describe the situation, my leadership actions, and the outcomes. Leadership is demonstrated through actions, not just titles.","Action-based leadership evidence presentation.","beginner"),
  q("sq-bg9-38",ip,"clinical_judgment","A patient develops acute pancreatitis with Cullen's sign.","What does Cullen's sign indicate in pancreatitis?","Cullen's sign—periumbilical ecchymosis—indicates retroperitoneal hemorrhage in severe necrotizing pancreatitis. Combined with Grey Turner's sign (flank ecchymosis), it suggests hemorrhagic pancreatitis with significant morbidity. I would monitor hemoglobin and hematocrit closely, ensure adequate IV access, anticipate possible blood transfusion, and prepare for possible ICU transfer.","Hemorrhagic pancreatitis recognition.","advanced"),
  q("sq-bg9-39",ip,"clinical_judgment","A patient on TPN develops hyperglycemia.","How would you manage TPN-associated hyperglycemia?","TPN-associated hyperglycemia occurs because of the high dextrose concentration. I would monitor blood glucose every 6 hours, administer insulin per sliding scale or continuous infusion as ordered, communicate the pattern to the provider for possible TPN formula adjustment, and watch for refeeding syndrome signs. Uncontrolled hyperglycemia during TPN increases infection risk.","TPN hyperglycemia management.","intermediate"),
  q("sq-bg9-40",ip,"clinical_judgment","A patient with myasthenia gravis develops respiratory weakness.","What is the critical concern with myasthenia gravis?","Myasthenic crisis—acute respiratory failure from muscle weakness—is the most dangerous complication. I would monitor FVC every 4 hours, watch for worsening dysphagia, weak cough, and dyspnea. If FVC drops below 15-20 mL/kg, the patient needs intubation. I would differentiate from cholinergic crisis by checking for excessive secretions, and avoid medications that worsen MG.","Myasthenic crisis monitoring with intubation criteria.","advanced"),
  q("sq-bg9-41",ws,"patient_safety","A patient develops acute urinary retention post-operatively.","How would you manage post-operative urinary retention?","I would assess for bladder distension using palpation or bedside ultrasound, try non-invasive measures first (running water, warm compress, ambulation), and prepare for intermittent catheterization if the patient cannot void within 6-8 hours post-operatively or has more than 300-400 mL on bladder scan. I would document voiding attempts and notify the provider.","Post-operative urinary retention management.","beginner"),
  q("sq-bg9-42",ws,"medication_error","A patient's medication list includes two drugs from the same class.","How would you identify therapeutic duplication?","I would question the duplication: 'I noticed the patient is prescribed both lisinopril and losartan—both are RAS inhibitors. Was this intentional, or should one be discontinued?' Therapeutic duplication increases adverse effect risk without proportional benefit. Pharmacist verification and provider clarification are essential before administering duplicate-class medications.","Therapeutic duplication identification.","intermediate"),
  q("sq-bg9-43",ct,"first_shift","You are asked to float to an unfamiliar unit.","How would you prepare for floating to an unfamiliar unit?","I would ask for a brief orientation: medication room, emergency equipment, unit-specific protocols, and patient population overview. I would request assignments within my competency level and identify a resource nurse on the unit. I would communicate any limitations honestly. Floating is common in nursing, and adaptability is a valued professional skill.","Float preparation and honest communication.","beginner"),
  q("sq-bg9-44",ct,"critical_thinking_drills","A patient's thyroid function shows elevated TSH with low free T4.","What does this thyroid pattern indicate?","Elevated TSH with low free T4 indicates primary hypothyroidism—the thyroid gland is not producing enough hormone, and the pituitary is compensating by increasing TSH stimulation. Symptoms include fatigue, weight gain, cold intolerance, constipation, and bradycardia. I would anticipate levothyroxine initiation and educate about medication timing (empty stomach, 30-60 minutes before eating).","Primary hypothyroidism lab interpretation.","beginner"),
  q("sq-bg9-45",pd,"advocacy","A patient needs home oxygen but faces insurance barriers.","How would you advocate for home oxygen coverage?","I would ensure thorough documentation of oxygen need with qualifying SpO2 levels, support the physician's letter of medical necessity, involve case management for insurance appeal, research alternative funding sources, and connect the patient with pulmonary support organizations. I would ensure the patient understands the appeal process and their rights.","Home oxygen insurance advocacy.","intermediate"),
  q("sq-bg9-46",ip,"clinical_judgment","A patient on chemotherapy develops febrile neutropenia.","How would you manage febrile neutropenia?","Febrile neutropenia (ANC <500 with fever >100.4°F) is an oncologic emergency. I would obtain blood cultures from all lumbar and peripheral sites, administer broad-spectrum antibiotics within 60 minutes of fever onset, implement neutropenic precautions, avoid rectal procedures, and monitor for sepsis progression. Time to antibiotics is the most critical factor in survival.","Febrile neutropenia emergency management.","advanced"),
  q("sq-bg9-47",ws,"handoff_communication","You are transferring a patient to a rehabilitation facility.","What information is essential for a rehab facility transfer?","I would provide: functional status baseline, therapy goals and progress, current medication list with last dose times, dietary requirements, cognitive status, fall risk assessment, wound care instructions, equipment needs, pain management plan, patient and family preferences, advance directives, and insurance authorization details.","Comprehensive rehab transfer communication.","beginner"),
  q("sq-bg9-48",pd,"patient_communication","A patient is frustrated with slow recovery progress.","How would you support a patient frustrated with their recovery pace?","I would validate their frustration while providing perspective: 'I understand your frustration—recovery does not always progress as quickly as we hope. Let me show you how far you have come since admission: you could not walk to the bathroom then, and now you are walking the hall. Recovery is not always linear, but you are making real progress.'","Progress perspective for frustrated patients.","beginner"),
  q("sq-bg9-49",cn,"career_advancement","You want to develop expertise in palliative care nursing.","How would you pursue palliative care nursing?","I would gain experience caring for patients with serious illness, pursue CHPN certification, develop expertise in symptom management and goals-of-care conversations, learn about grief counseling and family dynamics, and complete palliative care nursing education. Palliative care is about maximizing quality of life alongside curative treatment—it is not limited to end of life.","Palliative care nursing career pathway.","intermediate"),
  q("sq-bg9-50",ip,"clinical_judgment","A patient develops rhabdomyolysis after a fall with prolonged immobilization.","How would you manage rhabdomyolysis?","Rhabdomyolysis from muscle breakdown releases myoglobin, CK, and potassium into the bloodstream. I would administer aggressive IV fluid resuscitation to protect the kidneys, monitor CK levels, check for hyperkalemia and cardiac arrhythmias, monitor urine output and color (dark brown indicates myoglobinuria), and anticipate possible dialysis. Early aggressive hydration is the key intervention.","Rhabdomyolysis hydration-focused management.","advanced"),
  q("sq-bg9-51",ip,"clinical_judgment","A patient develops serotonin syndrome from drug interaction.","How would you recognize serotonin syndrome?","Serotonin syndrome presents with the triad of altered mental status, neuromuscular hyperactivity (clonus, tremor, rigidity), and autonomic instability (tachycardia, hyperthermia, diaphoresis). I would stop all serotonergic medications immediately, administer benzodiazepines for agitation, provide cooling measures, and administer cyproheptadine if ordered. This is caused by excessive serotonergic activity from drug combinations.","Serotonin syndrome recognition and management.","advanced"),
  q("sq-bg9-52",ws,"delegation","You need to delegate neurovascular checks to an LPN.","How would you delegate neurovascular assessments?","I would specify: 'Check circulation, sensation, and movement in both hands and feet every 2 hours. Compare bilateral findings. Report immediately: numbness, tingling, color change to white or blue, absent pulses, increased pain with movement, or swelling that prevents moving joints. Document each assessment with specific findings.'","Specific neurovascular check delegation.","beginner"),
  q("sq-bg9-53",ct,"documentation_challenges","You need to document a restraint assessment.","What does restraint documentation require?","I would document every 2 hours: circulatory status of restrained extremities, skin integrity under restraints, patient's emotional response, ongoing need assessment, alternatives attempted, release for ROM exercises and toileting, nutrition and hydration offered, and continued clinical justification. Restraint documentation is heavily regulated and audited.","Restraint assessment documentation requirements.","intermediate"),
  q("sq-bg9-54",pd,"ethical_dilemmas","A patient's surrogate decision-maker makes choices inconsistent with the patient's known wishes.","How would you address surrogate-patient wish conflicts?","I would document the patient's previously expressed wishes, share them with the healthcare team, advocate for an ethics consultation, and support the surrogate while gently redirecting: 'I understand this is difficult. Your mother told me before she lost capacity that she wanted comfort care. How can we honor her wishes while supporting you through this?'","Surrogate decision advocacy with patient's known wishes.","advanced"),
  q("sq-bg9-55",cn,"probation_period","You are struggling with a particular clinical skill.","How would you address a persistent skill deficit?","I would be specific about what I need: 'I am having difficulty with IV insertions in patients with difficult access. Could I spend time in the IV team or practice in simulation? I want to develop this skill systematically rather than just hoping it improves with time.' Targeted practice is more effective than general experience.","Specific skill deficit remediation request.","beginner"),
  q("sq-bg9-56",ip,"clinical_judgment","A patient with acute coronary syndrome is allergic to aspirin.","What alternative is used for aspirin-allergic ACS patients?","For aspirin-allergic ACS patients, clopidogrel or ticagrelor is used as an alternative antiplatelet agent. In some cases, aspirin desensitization may be performed. I would verify the nature of the aspirin allergy (true allergy vs. sensitivity), communicate it clearly to the interventional team, and ensure the alternative antiplatelet is administered promptly.","ACS management in aspirin allergy.","advanced"),
  q("sq-bg9-57",ws,"patient_safety","A patient on continuous pulse oximetry has persistent false low readings.","How would you troubleshoot persistent false low SpO2?","I would check: sensor placement, patient's circulation (cold fingers reduce accuracy), nail polish or artificial nails, patient movement, ambient light interference, and sensor condition. I would try an ear or forehead probe. I would correlate with clinical assessment—if the patient appears comfortable and well-perfused, the reading may be artifactual.","SpO2 troubleshooting beyond simple repositioning.","beginner"),
  q("sq-bg9-58",ct,"time_management","You are a slow medication passer and it affects your entire shift.","How would you improve medication pass efficiency?","I would prepare by reviewing medication lists before starting, organizing medications by room order, batching PRN assessments with scheduled medication times, using the scanner efficiently, and minimizing interruptions during passes. I would time myself to identify bottlenecks and observe faster nurses' techniques. Medication pass efficiency improves patient safety by reducing rushing.","Medication pass efficiency analysis.","beginner"),
  q("sq-bg9-59",pd,"patient_communication","A patient is angry that a procedure was delayed.","How would you manage anger about procedural delays?","I would validate the frustration: 'I completely understand your frustration. Waiting when you are anxious about a procedure is very stressful. Let me find out the current status and give you a realistic timeline. Is there anything I can do to make the wait more comfortable?' Transparency about delays reduces anger more than apologies.","Procedure delay communication with transparency.","beginner"),
  q("sq-bg9-60",cn,"career_advancement","You are interested in nursing administration.","How would you pursue nursing administration?","I would develop leadership skills through charge nurse roles, pursue MSN in nursing administration or MBA/MHA, learn about healthcare finance, regulatory compliance, and quality metrics, participate in hospital committees, and network with current administrators. Administrative nursing requires balancing clinical knowledge with business acumen.","Nursing administration career pathway.","intermediate"),
  q("sq-bg9-61",ip,"clinical_judgment","A patient develops acute adrenal crisis.","How would you recognize and manage adrenal crisis?","Adrenal crisis presents with severe hypotension, hyponatremia, hyperkalemia, hypoglycemia, and altered consciousness. It can be triggered by illness, stress, or abrupt steroid withdrawal. I would administer IV hydrocortisone 100mg immediately, provide aggressive IV normal saline resuscitation, correct hypoglycemia with dextrose, and support hemodynamics. This is a medical emergency.","Adrenal crisis emergency management.","advanced"),
  q("sq-bg9-62",ws,"medication_error","A patient's medication dose seems unusually high compared to normal ranges.","How would you verify an unusually high medication dose?","I would not administer it without verification. I would check the drug reference for maximum dose ranges, review the patient's weight and renal function for dose appropriateness, contact the pharmacist for verification, and clarify with the prescriber if the dose exceeds normal ranges. I would document my verification process.","Dose verification for unusually high orders.","beginner"),
  q("sq-bg9-63",ct,"critical_thinking_drills","A patient's troponin-I is 0.08 ng/mL.","Is this troponin level concerning?","Troponin-I of 0.08 (normal <0.04 ng/mL) is mildly elevated, indicating some degree of myocardial injury. This does not necessarily mean MI—troponin can be elevated in heart failure, PE, myocarditis, sepsis, and renal failure. Serial troponins showing a rise-and-fall pattern suggest acute MI. I would correlate with symptoms, ECG, and clinical context.","Mild troponin elevation interpretation with differential.","intermediate"),
  q("sq-bg9-64",pd,"advocacy","A patient needs a medication they cannot afford.","How would you help a patient access unaffordable medications?","I would research manufacturer patient assistance programs, check for generic alternatives, involve social work for financial assistance, explore pharmacy discount programs, investigate community health center dispensaries, and ensure the prescriber knows about the financial barrier so they can consider alternatives. Medication affordability is a critical factor in treatment compliance.","Medication affordability resource mobilization.","beginner"),
  q("sq-bg9-65",ip,"clinical_judgment","A patient on dialysis develops disequilibrium syndrome.","What is dialysis disequilibrium syndrome?","Dialysis disequilibrium syndrome occurs when rapid solute removal during dialysis creates an osmotic gradient, causing cerebral edema. Symptoms include headache, nausea, confusion, and seizures. I would slow the dialysis rate, administer mannitol or hypertonic saline per orders, and monitor neurological status. Prevention involves slower initial dialysis sessions for new dialysis patients.","Dialysis disequilibrium syndrome management.","advanced"),
  q("sq-bg9-66",ws,"difficult_coworkers","A colleague frequently borrows supplies from your patient's room.","How would you address supply borrowing?","I would address it constructively: 'I have noticed supplies disappearing from my patients' rooms, which means I need to restock during busy times. Can we discuss a better system for supply sharing that does not leave any patient's room depleted?' Supply availability directly affects care efficiency.","Supply management communication.","beginner"),
  q("sq-bg9-67",ct,"new_nurse_anxiety","You feel like every shift is a struggle.","When does the first year of nursing get easier?","Most nurses report significant improvement around 6-12 months. The first 3 months are the hardest—everything is new and takes longer. By 6 months, routine tasks become automatic. By 12 months, most nurses feel competent and confident in their daily practice. The learning curve is steep but it does plateau. Be patient with yourself.","First-year nursing timeline expectations.","beginner"),
  q("sq-bg9-68",pd,"professional_boundaries","You develop a friendship with a patient during a long hospital stay.","How would you manage a developing patient friendship?","I would maintain professional awareness while being warm: provide excellent care, share appropriate personal information, but avoid exchanging contact information or planning post-discharge meetings. After discharge, the relationship should end. If I feel the boundary is blurring, I would discuss it with my charge nurse. Therapeutic relationships have boundaries for good reason.","Long-stay patient boundary management.","beginner"),
  q("sq-bg9-69",cn,"job_offer_negotiation","The interviewer asks about your experience with diversity.","How would you discuss diversity experience in an interview?","I would share specific examples: 'During my community health rotation, I worked with diverse populations including refugees, LGBTQ+ individuals, and people experiencing homelessness. I learned that effective nursing requires understanding each patient's unique cultural context, health beliefs, and barriers to care. I am committed to providing equitable care for all patients.'","Specific diversity experience with equity commitment.","beginner"),
  q("sq-bg9-70",ip,"clinical_judgment","A patient develops peritonitis after a perforated appendix.","How would you manage peritonitis?","Peritonitis presents with rigid, board-like abdomen, severe pain, fever, and signs of sepsis. I would keep the patient NPO, ensure IV antibiotics are administered immediately, prepare for possible emergency surgery, insert an NG tube if ordered, administer IV fluids aggressively, and monitor closely for septic shock progression.","Peritonitis emergency management.","intermediate"),
  q("sq-bg9-71",ws,"patient_safety","A patient with a tracheostomy has the inner cannula become occluded.","How would you manage a tracheostomy obstruction?","I would remove the inner cannula immediately, clean or replace it, and suction the tracheostomy. If the obstruction is in the outer cannula, I would call for help, prepare for possible tracheostomy change, and keep emergency airway equipment at bedside including a spare tracheostomy tube one size smaller. If the patient cannot be ventilated, I would prepare for oral intubation.","Tracheostomy obstruction emergency management.","intermediate"),
  q("sq-bg9-72",ct,"documentation_challenges","You need to document a complex multidisciplinary discussion.","How would you document an interdisciplinary care conference?","I would document: date, time, attendees and their disciplines, topics discussed, decisions made, action items with responsible parties, patient and family participation, goals of care updates, and any changes to the care plan. This documentation ensures all team members can reference the decisions even if they were not present.","Interdisciplinary conference documentation.","beginner"),
  q("sq-bg9-73",pd,"ethical_dilemmas","A terminally ill patient asks about physician-assisted death.","How would you respond to questions about physician-assisted death?","I would respond compassionately: 'I hear that your suffering is significant. Let me make sure we are addressing your pain and symptoms optimally first. Regarding your question about end-of-life options, I can connect you with our palliative care team and social worker who can discuss all available options in your state.' I would follow state laws and facility policies.","Compassionate end-of-life options discussion.","advanced"),
  q("sq-bg9-74",cn,"career_advancement","You want to combine clinical practice with teaching.","How would you pursue a clinical educator role?","I would develop expertise in my clinical area, pursue a graduate degree in nursing education, gain precepting experience, develop presentation and curriculum design skills, and seek adjunct faculty positions. Clinical educators bridge the gap between academia and practice—they need current clinical competence alongside teaching methodology.","Clinical educator career pathway.","intermediate"),
  q("sq-bg9-75",ip,"clinical_judgment","A patient with chronic kidney disease has a GFR of 12.","What does a GFR of 12 indicate?","GFR of 12 mL/min indicates stage 5 CKD (end-stage renal disease—normal >90). The patient likely needs renal replacement therapy (dialysis or transplantation). I would assess for uremic symptoms, monitor electrolytes closely, ensure renal-dosed medications, provide dietary education on potassium and phosphorus restriction, and facilitate nephrology consultation and dialysis access planning.","Stage 5 CKD management and dialysis preparation.","advanced"),
  q("sq-bg9-76",ws,"interdisciplinary_communication","A psychiatrist recommends a treatment plan that conflicts with the medical team's approach.","How would you navigate psychiatric-medical treatment conflicts?","I would facilitate communication between both teams: 'There seems to be a conflict between the psychiatric recommendation for [treatment] and the medical team's concern about [issue]. Can we arrange a combined care conference to develop a unified plan that addresses both the patient's psychiatric and medical needs?'","Psychiatric-medical team conflict mediation.","intermediate"),
  q("sq-bg9-77",ct,"critical_thinking_drills","A patient's BUN/creatinine ratio is 35:1.","What does a high BUN/creatinine ratio indicate?","A BUN/creatinine ratio above 20:1 suggests prerenal azotemia—the kidneys are not receiving adequate blood flow. Common causes include dehydration, heart failure, and GI bleeding. A ratio of 35:1 strongly suggests hypovolemia or GI bleeding (blood is a protein source that raises BUN). I would assess volume status and check for GI bleeding signs.","BUN/creatinine ratio interpretation.","intermediate"),
  q("sq-bg9-78",pd,"patient_communication","A patient with dementia is agitated and confused.","How would you communicate with an agitated dementia patient?","I would use a calm, low tone of voice, approach from the front, use simple sentences, avoid arguing or correcting delusions, redirect attention rather than confronting, ensure the environment is calm and familiar, address potential causes of agitation (pain, hunger, toileting needs), and use familiar objects or music for comfort.","Dementia-specific therapeutic communication.","intermediate"),
  q("sq-bg9-79",cn,"performance_evaluation","You want to negotiate for a schedule change during your evaluation.","How would you request a schedule change professionally?","I would frame it as mutual benefit: 'I have noticed that my performance and energy are strongest on specific shift patterns. I would like to discuss adjusting my schedule to [specific request]. I believe this change would improve my clinical performance and reduce my fatigue-related error risk, benefiting both my patients and the unit.'","Performance-based schedule change request.","beginner"),
  q("sq-bg9-80",ip,"clinical_judgment","A patient develops refeeding syndrome after nutritional supplementation.","What is refeeding syndrome?","Refeeding syndrome occurs when malnourished patients receive nutrition too rapidly, causing electrolyte shifts—particularly hypophosphatemia, hypokalemia, and hypomagnesemia—as cells shift from fat to glucose metabolism. This can cause cardiac failure, respiratory failure, and death. I would start nutrition slowly, supplement phosphorus and thiamine proactively, and monitor electrolytes every 12 hours during initial refeeding.","Refeeding syndrome prevention and management.","advanced"),
  q("sq-bg9-81",ws,"patient_safety","A patient with a history of anaphylaxis needs a new medication.","How would you ensure safe first-dose administration for anaphylaxis-risk patients?","I would verify the medication is not cross-reactive with known allergens, ensure epinephrine and emergency equipment are immediately available, administer the first dose in a monitored setting, observe for at least 30 minutes after administration, and educate the patient about symptoms to report. For high-risk medications, I would discuss desensitization with the allergist.","Anaphylaxis-aware first-dose safety.","intermediate"),
  q("sq-bg9-82",ct,"time_management","You are asked to precept a nursing student while managing your full assignment.","How would you balance precepting with patient care?","I would involve the student in my workflow rather than adding tasks: 'Let me show you how I organize my shift while we care for patients together.' I would identify specific learning opportunities aligned with my care activities, set clear expectations, and communicate honestly about when I need to focus without teaching. Student education should enhance, not compromise, patient care.","Integrated precepting with workflow.","beginner"),
  q("sq-bg9-83",pd,"workplace_bullying","A nurse uses patient assignments as punishment.","How would you address punitive assignment practices?","I would document the pattern with specific examples and present it to the manager: 'I have noticed that assignments following [specific interactions] consistently include the most challenging patients. I believe assignments should be based on clinical acuity and equitable distribution rather than interpersonal dynamics.' I would involve HR if the behavior continued.","Punitive assignment pattern documentation.","intermediate"),
  q("sq-bg9-84",cn,"career_advancement","You want to develop expertise in psychiatric nursing.","How would you specialize in psychiatric nursing?","I would gain experience in an inpatient psychiatric unit, pursue PMH-BC certification, develop expertise in therapeutic communication, crisis intervention, and psychopharmacology, learn about trauma-informed care, and understand legal aspects of psychiatric nursing including involuntary commitment. Psychiatric nursing requires strong self-awareness and emotional intelligence.","Psychiatric nursing specialization pathway.","intermediate"),
  q("sq-bg9-85",ip,"clinical_judgment","A patient with CHF has a weight gain of 5 pounds overnight.","What does rapid weight gain in CHF indicate?","Rapid weight gain of 5 pounds overnight in a CHF patient indicates acute fluid retention—approximately 2.3 liters of excess fluid. I would assess for worsening heart failure signs: dyspnea, orthopnea, JVD, lung crackles, and peripheral edema. I would notify the provider for diuretic adjustment, implement fluid restriction, and monitor daily weights and I&O strictly.","CHF fluid retention assessment.","intermediate"),
  q("sq-bg9-86",ws,"medication_error","A patient questions why they are receiving a different brand of their medication.","How would you address brand substitution concerns?","I would explain: 'The hospital pharmacy uses a different manufacturer, but the active medication is identical. The pills may look different in shape or color, but the drug inside works the same way. If you ever question any medication, please always tell us—we appreciate patients who are vigilant about their medications.'","Brand substitution education with patient validation.","beginner"),
  q("sq-bg9-87",ct,"first_shift","You feel like you do not belong on your unit.","How would you manage feeling like an outsider?","I would remind myself that integration takes time—most new nurses feel like outsiders for the first few months. I would make small connections: introduce myself to a new colleague each shift, participate in team huddles, volunteer for unit activities, and demonstrate consistent, reliable care. Belonging develops through shared experiences and mutual trust.","Integration strategies for feeling like an outsider.","beginner"),
  q("sq-bg9-88",pd,"advocacy","A patient needs a specific medical device that the hospital does not stock.","How would you obtain a non-stocked medical device?","I would contact the supply chain department, research available alternatives, check with other units for borrowed equipment, contact the manufacturer for urgent supply, and escalate through the charge nurse if the device is clinically necessary. I would document the clinical need and the delay. No patient should go without essential equipment due to stocking gaps.","Non-stocked equipment procurement advocacy.","intermediate"),
  q("sq-bg9-89",ip,"clinical_judgment","A patient develops Addisonian crisis during an acute illness.","What triggers Addisonian crisis and how is it managed?","Addisonian crisis occurs when patients with chronic adrenal insufficiency face physiological stress without adequate steroid supplementation. It presents with severe hypotension, hyponatremia, hyperkalemia, and shock. I would administer stress-dose hydrocortisone IV immediately, provide aggressive fluid resuscitation with NS and dextrose, and treat the underlying stressor.","Addisonian crisis recognition and stress-dose steroids.","advanced"),
  q("sq-bg9-90",ws,"handoff_communication","You are giving report to the oncoming shift and a physician calls with new orders.","How would you manage concurrent handoff and new orders?","I would pause the handoff briefly: 'Excuse me—I need to take this physician call about new orders.' I would take the order, read it back, integrate the new information into my ongoing handoff, and ensure the receiving nurse understands the new orders and their clinical context. New orders during handoff need to be communicated immediately.","Concurrent handoff and order management.","beginner"),
  q("sq-bg9-91",ct,"critical_thinking_drills","A patient's D-dimer is 800 ng/mL with leg swelling.","How would you interpret D-dimer with clinical correlation?","D-dimer of 800 (normal <500) combined with unilateral leg swelling increases the probability of DVT. D-dimer is a sensitive but non-specific test—it is useful for ruling out VTE when negative but cannot confirm it when positive. I would calculate the Wells score and advocate for definitive imaging (duplex ultrasound) given the clinical presentation.","D-dimer clinical correlation with Wells scoring.","intermediate"),
  q("sq-bg9-92",pd,"ethical_dilemmas","You are asked to care for a patient whose values you strongly disagree with.","How would you provide equitable care despite value disagreements?","I would separate my personal values from my professional obligation. Every patient deserves equitable, competent care regardless of their beliefs, lifestyle, or past actions. If my feelings significantly impair my ability to provide unbiased care, I would request reassignment without judgment. Professional ethics require us to care for all patients equally.","Value neutrality in professional care.","intermediate"),
  q("sq-bg9-93",cn,"career_advancement","You want to develop your mentoring skills.","How would you become an effective mentor?","I would develop active listening skills, learn coaching techniques, study adult learning principles, practice giving constructive feedback, and seek formal mentor training. Effective mentoring requires patience, availability, and genuine investment in the mentee's growth. I would start by volunteering to precept students and new graduates.","Mentoring skill development.","beginner"),
  q("sq-bg9-94",ip,"clinical_judgment","A patient develops posterior fossa syndrome after brain surgery.","What is posterior fossa syndrome?","Posterior fossa syndrome (cerebellar mutism) can occur after surgery near the cerebellum, presenting with mutism, emotional lability, and ataxia. It typically appears 24-48 hours post-operatively and can last weeks to months. I would ensure communication alternatives are available, provide emotional support, coordinate with speech therapy, and reassure the family that recovery, while slow, usually occurs.","Posterior fossa syndrome recognition and support.","advanced"),
  q("sq-bg9-95",ws,"patient_safety","A patient is at risk for refeeding syndrome.","How would you identify refeeding risk patients?","Risk factors include: BMI below 16, weight loss greater than 15% in 3-6 months, minimal nutritional intake for more than 10 days, and low baseline phosphorus, magnesium, or potassium. For at-risk patients, I would start nutrition slowly (10-20 kcal/kg/day), supplement thiamine and phosphorus prophylactically, and monitor electrolytes daily during the first week of refeeding.","Refeeding risk identification and prevention.","intermediate"),
  q("sq-bg9-96",ct,"documentation_challenges","You need to document multiple rapid assessments during an emergency.","How would you document during a fast-paced emergency?","I would designate someone to document or use the time-stamp feature in the EHR to document key events in real-time. After the emergency, I would complete a detailed chronological narrative within 24 hours while the events are fresh. I would include my assessments, interventions, patient responses, and all communications. Emergency documentation should tell the complete story.","Emergency documentation strategies.","intermediate"),
  q("sq-bg9-97",pd,"patient_communication","A patient with limited English proficiency needs consent education.","How would you ensure informed consent with a language barrier?","I would arrange a certified medical interpreter—never family members for consent discussions. I would allow extra time, use visual aids, verify understanding through interpreted teach-back, and ensure all consent documents are available in the patient's language. I would document the interpretation method used and the patient's demonstrated understanding.","Language-barrier informed consent process.","intermediate"),
  q("sq-bg9-98",cn,"probation_period","You want to build relationships with experienced nurses.","How would you connect with experienced nurses during orientation?","I would show genuine respect for their experience, ask for advice about specific clinical situations, express appreciation for their guidance, offer to help with tasks, and demonstrate reliability. I would not try too hard or be overly familiar—professional relationships develop naturally through shared patient care experiences and mutual respect.","Natural relationship building with experienced staff.","beginner"),
  q("sq-bg9-99",ip,"clinical_judgment","A patient develops transfusion-related acute lung injury.","How would you manage TRALI?","TRALI presents with acute respiratory distress, bilateral infiltrates, and hypoxemia within 6 hours of transfusion—without fluid overload signs. I would stop the transfusion immediately, provide supportive respiratory care including possible intubation, notify the blood bank, and send the blood product and samples for testing. Unlike TACO, TRALI does not respond to diuretics.","TRALI recognition and management versus TACO.","advanced"),
  q("sq-bg9-100",ws,"interdisciplinary_communication","A palliative care team recommends comfort measures but the patient's family is not ready.","How would you facilitate the transition to comfort care?","I would support the family through their grief process: 'This is an incredibly difficult decision. The palliative care team's recommendation is based on their assessment that aggressive treatment is no longer helping. Let me arrange a meeting where you can ask questions and express your concerns. There is no rush to make this decision today.'","Comfort care transition family support.","intermediate"),
  q("sq-bg9-101",ip,"clinical_judgment","A patient on warfarin needs an emergency surgery.","How would you prepare an anticoagulated patient for emergency surgery?","I would check the INR immediately, administer vitamin K (phytonadione) IV as ordered for reversal, prepare fresh frozen plasma or prothrombin complex concentrate for rapid reversal, communicate the INR and reversal status to the surgical team, and ensure blood products are available. Emergency reversal is faster with PCC than FFP.","Emergency anticoagulation reversal for surgery.","advanced"),
  q("sq-bg9-102",ct,"critical_thinking_drills","A patient's lactate dehydrogenase is 500 U/L.","What does elevated LDH indicate?","LDH of 500 (normal 120-246) is a non-specific marker of tissue damage. It is elevated in hemolysis, liver disease, myocardial infarction, pulmonary embolism, malignancy, and rhabdomyolysis. The clinical context determines its significance. I would correlate with other labs: elevated haptoglobin and indirect bilirubin suggest hemolysis; elevated AST/ALT suggests liver disease.","LDH interpretation with clinical correlation.","intermediate"),
  q("sq-bg9-103",pd,"advocacy","A patient's religious beliefs require specific care accommodations.","How would you advocate for religious care accommodations?","I would document the specific religious requirements, communicate them to the care team, arrange accommodations when possible (prayer times, dietary laws, modesty requirements, same-gender caregivers), and involve the chaplain for guidance. I would ensure the accommodation plan is in the care plan and communicated during handoff. Religious accommodations are part of holistic patient care.","Religious accommodation advocacy.","beginner"),
  q("sq-bg9-104",cn,"career_advancement","You want to develop expertise in pediatric nursing.","How would you pursue pediatric nursing?","I would gain experience in a pediatric unit, pursue CPN certification, develop skills in pediatric assessment and developmental stages, learn about family-centered care, and understand common pediatric conditions and their management. Pediatric nursing requires strong family communication skills and the ability to adapt care to developmental levels.","Pediatric nursing specialization pathway.","intermediate"),
  q("sq-bg9-105",ws,"patient_safety","A patient develops an air embolism during IV medication administration.","How would you manage an air embolism during IV therapy?","I would clamp the IV line immediately, position the patient in left lateral Trendelenburg (Durant's maneuver) to trap air in the right ventricle apex, administer 100% oxygen, call for help, and notify the physician. Prevention is key: always prime tubing completely, use air-detecting IV pumps, and remove air from syringes before injection.","Air embolism management during IV therapy.","intermediate"),
  q("sq-bg9-106",ip,"clinical_judgment","A patient develops contrast-induced nephropathy after a CT scan.","How would you manage contrast-induced nephropathy?","I would ensure adequate IV hydration before and after contrast administration, monitor creatinine levels at 24-48 hours post-contrast, ensure the patient is not on nephrotoxic medications, and check urine output. For high-risk patients (existing CKD, diabetes), prevention with hydration and possibly N-acetylcysteine is more effective than treatment.","Contrast nephropathy prevention and monitoring.","intermediate"),
  q("sq-bg9-107",ct,"new_nurse_anxiety","You feel like your nursing education did not prepare you adequately.","How would you bridge the education-practice gap?","I would recognize that no educational program can fully prepare you for clinical reality—the gap is normal and expected. I would focus on applying my foundational knowledge to real situations, ask experienced nurses how they bridge theory to practice, and identify specific knowledge gaps to address through targeted learning. The gap closes with experience and intentional learning.","Education-practice gap normalization.","beginner"),
  q("sq-bg9-108",pd,"ethical_dilemmas","You suspect a patient is being financially exploited by a caregiver.","How would you address suspected financial exploitation?","I would document my observations (signs of neglect despite reported adequate resources, caregiver controlling finances), involve social work, report to Adult Protective Services as a mandatory reporter, and ensure the patient's immediate needs are being met. Financial exploitation of vulnerable adults is a reportable offense in all states.","Financial exploitation mandatory reporting.","intermediate"),
  q("sq-bg9-109",cn,"career_advancement","You are interested in informatics nursing.","How would you pursue nursing informatics?","I would develop technical skills in EHR systems, learn about health data analytics and clinical decision support, pursue ANCC informatics certification, understand workflow analysis and system implementation, and consider a graduate degree in nursing informatics. Informatics nurses bridge clinical practice and health information technology.","Nursing informatics career pathway.","intermediate"),
  q("sq-bg9-110",ws,"medication_error","A patient's medication reconciliation reveals discrepancies with home medications.","How would you resolve medication reconciliation discrepancies?","I would verify the home medication list with the patient, contact their home pharmacy, compare with the current hospital medication list, identify discrepancies, and communicate them to the prescriber for resolution. Medication reconciliation errors are a leading cause of adverse events during care transitions.","Medication reconciliation discrepancy resolution.","beginner"),
  q("sq-bg9-111",ip,"clinical_judgment","A patient develops hemolytic uremic syndrome.","How would you manage HUS?","HUS presents with microangiopathic hemolytic anemia, thrombocytopenia, and acute renal failure—often triggered by E. coli O157:H7 infection. I would monitor renal function and urine output closely, provide supportive care including IV fluids and blood product support, monitor for seizures and hypertension, and prepare for possible dialysis. Platelet transfusion is generally avoided as it can worsen thrombotic microangiopathy.","HUS management with platelet transfusion caution.","advanced"),
  q("sq-bg9-112",ct,"critical_thinking_drills","A patient's ferritin is 15 ng/mL.","What does a low ferritin indicate?","Ferritin of 15 (normal 20-250 for women, 20-500 for men) indicates iron deficiency—the most common cause of anemia worldwide. I would assess for iron-deficiency symptoms (fatigue, pallor, pica, restless legs), review dietary iron intake, check for blood loss sources (menstruation, GI bleeding), and anticipate iron supplementation. Ferritin is the most specific test for iron deficiency.","Ferritin as iron deficiency indicator.","beginner"),
  q("sq-bg9-113",ws,"handoff_communication","You are transferring a patient to another hospital.","What is essential for an inter-facility transfer handoff?","I would provide: complete medical records, current medication list with last dose times, IV and drip information, current vital signs and trends, all imaging and lab results, advance directives, insurance information, family contact details, and a concise clinical summary. I would include a verbal report to the receiving nurse covering key clinical concerns and the reason for transfer.","Comprehensive inter-facility transfer communication.","intermediate"),
  q("sq-bg9-114",pd,"patient_communication","A patient needs to understand their discharge medications.","How would you conduct effective discharge medication education?","I would review each medication individually: name, purpose, dose, timing, important side effects, and what to do if a dose is missed. I would use the teach-back method after each medication. I would provide a written medication schedule with pill appearance descriptions. I would ensure they understand which medications are new versus continued from before hospitalization.","Comprehensive discharge medication education.","beginner"),
  q("sq-bg9-115",cn,"career_advancement","You want to develop research skills as a bedside nurse.","How would you engage in nursing research from the bedside?","I would start with clinical inquiry: 'Why do we do this procedure this way? Is there evidence for a better approach?' I would learn to search nursing databases, critically appraise research articles, participate in evidence-based practice committees, and contribute to data collection for ongoing studies. Bedside nurses are essential partners in clinical research.","Bedside nursing research engagement.","beginner"),
  q("sq-bg9-116",ip,"clinical_judgment","A patient develops anemia of chronic disease.","How does anemia of chronic disease differ from iron deficiency?","In ACD, ferritin is usually normal or elevated (iron is sequestered in storage), while in iron deficiency, ferritin is low. ACD results from chronic inflammation suppressing red blood cell production. Treatment focuses on managing the underlying disease rather than iron supplementation. TIBC is low in ACD but elevated in iron deficiency—a key differentiator.","ACD versus iron deficiency differentiation.","intermediate"),
  q("sq-bg9-117",ws,"patient_safety","A patient on contact precautions needs emergent transport to radiology.","How would you maintain precautions during emergent transport?","I would apply appropriate PPE, cover the patient appropriately, notify the receiving department about precautions, ensure the stretcher is cleaned after transport, and maintain hand hygiene. For emergent situations, I would balance precaution maintenance with transport urgency. I would ensure the radiology team is prepared with appropriate PPE.","Emergent transport precaution maintenance.","beginner"),
  q("sq-bg9-118",ct,"documentation_challenges","You need to document a rapid response event.","What should rapid response documentation include?","I would document: time of event recognition, initial assessment findings, time rapid response was activated, team members who responded, interventions performed with times, patient responses, vital sign changes throughout, physician orders received, patient disposition, and any family communication. Chronological accuracy is critical for rapid response documentation.","Rapid response event documentation.","intermediate"),
  q("sq-bg9-119",pd,"workplace_bullying","A senior nurse withholds important patient information as a power tactic.","How would you address information withholding?","I would address it directly: 'I need complete patient information to provide safe care. When critical information is withheld, patient safety is compromised. I am requesting that all relevant clinical information be shared during handoff and throughout the shift.' If the behavior continued, I would document specific instances and report to management.","Information withholding as patient safety issue.","intermediate"),
  q("sq-bg9-120",cn,"probation_period","You are approaching the end of your probation period with mixed feelings.","How would you assess your readiness for probation completion?","I would evaluate honestly: Can I manage my patient assignment safely? Do I know when to ask for help? Am I comfortable with the most common situations on my unit? Do I have a resource network? If I have areas of concern, I would discuss them with my manager proactively rather than waiting for the evaluation. Honest self-assessment demonstrates professional maturity.","Honest probation readiness self-assessment.","beginner"),
];
